const driveFileId = $('Upload to Drive').item.json.id;
const driveLink = `https://drive.google.com/file/d/${driveFileId}/view`;
const ocrResponse = $input.item.json;
const rawText = ocrResponse.ParsedResults?.[0]?.ParsedText || '';
const lines = rawText.split('\n').map(l => l.trim()).filter(Boolean);

// Extract amount — find all numbers, take the largest as total
const amountRegex = /(?:rs\.?|inr|\u20b9|total|amount)[\s:]*([\d,]+(?:\.\d{2})?)|([\d,]{3,}(?:\.\d{2})?)/gi;
const amounts = [];
let m;
while ((m = amountRegex.exec(rawText)) !== null) {
  const val = parseFloat((m[1] || m[2]).replace(/,/g, ''));
  if (!isNaN(val) && val > 0 && val < 1000000) amounts.push(val);
}
const amount = amounts.length > 0 ? Math.max(...amounts) : 0;

// Extract date
const dateRegex = /(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})/;
const dateMatch = rawText.match(dateRegex);
let date;
if (dateMatch) {
  const y = dateMatch[3].length === 2 ? '20' + dateMatch[3] : dateMatch[3];
  date = `${y}-${dateMatch[2].padStart(2,'0')}-${dateMatch[1].padStart(2,'0')}`;
} else {
  date = new Date().toISOString().split('T')[0];
}

// Extract merchant — first meaningful line
const skipWords = ['gstin','gst','tax','invoice','receipt','bill','total','amount','date','thank','welcome'];
let merchant = 'Unknown';
for (const line of lines) {
  const lower = line.toLowerCase();
  const hasSkip = skipWords.some(w => lower.includes(w));
  const hasDigit = /\d{5,}/.test(line);
  if (!hasSkip && !hasDigit && line.length > 2 && line.length < 50) {
    merchant = line;
    break;
  }
}

// Extract payment method
const payMap = { upi: 'UPI', gpay: 'UPI', paytm: 'UPI', phonepe: 'UPI', cash: 'Cash', card: 'Card', credit: 'Card', debit: 'Card', neft: 'NEFT', rtgs: 'RTGS', cheque: 'Cheque' };
let paymentMethod = 'Unknown';
const lowerText = rawText.toLowerCase();
for (const [key, val] of Object.entries(payMap)) {
  if (lowerText.includes(key)) { paymentMethod = val; break; }
}

// Get user's caption note if any
const userNote = $('Telegram Trigger').item.json.message?.caption || '';

return [{ json: { amount, date, merchant, paymentMethod, userNote, driveLink, rawText, ocrSuccess: rawText.length > 10 } }];

const input = $input.item.json;
const text = (input.rawText + ' ' + input.merchant).toLowerCase();
const userNote = (input.userNote || '').toLowerCase();
const forceBusiness = userNote.startsWith('b:');

const rules = [
  { category: 'Food & Drink', type: 'Personal', keywords: ['zomato','swiggy','starbucks','cafe','restaurant','biryani','pizza','food','eat','dominos','mcdonald','kfc','burger','dine'] },
  { category: 'Transport', type: 'Personal', keywords: ['uber','ola','rapido','petrol','fuel','toll','parking','auto','cab','rickshaw','metro','bus fare','train fare'] },
  { category: 'Shopping', type: 'Personal', keywords: ['amazon','flipkart','myntra','mall','store','shop','meesho','snapdeal','ajio','retail'] },
  { category: 'Bills & Utilities', type: 'Personal', keywords: ['electricity','water','broadband','jio','airtel','bsnl','recharge','bill','internet','wifi','gas cylinder','piped gas'] },
  { category: 'Medical', type: 'Personal', keywords: ['pharmacy','hospital','doctor','clinic','medicine','apollo','medplus','1mg','netmeds','health','dental','lab test'] },
  { category: 'Business - Software', type: 'Business', keywords: ['aws','google cloud','notion','slack','zoom','adobe','subscription','saas','github','figma','canva','digitalocean','heroku'] },
  { category: 'Business - Travel', type: 'Business', keywords: ['flight','hotel','train ticket','business travel','airport','business cab'] },
  { category: 'Business - Meals', type: 'Business', keywords: ['client lunch','vendor meeting','team lunch','business meal','office lunch','client dinner'] },
  { category: 'Business - Supplies', type: 'Business', keywords: ['office supplies','stationery','equipment','printer','laptop','monitor','business supplies'] },
  { category: 'Vendor Payment', type: 'Business', keywords: ['vendor','supplier','contractor','invoice payment','advance payment'] },
  { category: 'Cash', type: 'Personal', keywords: ['atm','cash withdrawal','cash advance'] },
];

let category = 'Other';
let type = 'Personal';

for (const rule of rules) {
  if (rule.keywords.some(kw => text.includes(kw) || userNote.includes(kw))) {
    category = rule.category;
    type = rule.type;
    break;
  }
}

if (forceBusiness) type = 'Business';

return [{ json: { ...input, category, type } }];

